//Valida que la cantidad sea positiva 
function cantidad_onvalidate(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{	
		if (Number(Ctrl('n_cantidad').GetXValue())<=0)
		{
			pObj.SetError('La cantidad debe ser mayor a 0.');
			return false;
		}
	}
	return true;
}


function n_iva_onvalidate(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{	
		if(c_letra!='C' && c_letra!='X')
		{
			if (Number(Ctrl('n_iva').GetXValue())<=0)
			{
				pObj.SetError('El importe IVA debe ser mayor a 0.');
				return false;
			}
		}
	}
	return true;
}


//Valida que el precio sea positivo
function precio_onvalidate(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{	
		if (Number(Ctrl('n_precio_unitario').GetXValue())<=0)
		{
			pObj.SetError('El precio unitario debe ser mayor a 0.');
			return false;
		}
	}
	return true;
}


//Calcula el importe del IVA si cambia el impuesto
function impuesto_onchange()
{
	get_porcentaje();	
	calcular_iva();
	calcular_total();	
}


//Recupera el porcentaje correspondiente al impuesto seleccionado
function get_porcentaje()
{	
	var oi_impuesto = Ctrl('oi_impuesto').GetXValue();

	if (oi_impuesto!='')
	{	
	  var nSQL = GetProxy().SQLService();	 
		var xmlParam = new NomadXML('DATA');
		xmlParam.SetAttr('oi_impuesto',oi_impuesto);				
		var objPorc = nSQL.GetOBJ(Ctrl("main").getResource("GetPorcentaje"),xmlParam.ToString()); 
  	Ctrl('n_porcentaje').SetXValue(Number(objPorc.n_porcentaje));
	}
	else
	{
		Ctrl('n_porcentaje').SetXValue();
	}
}


function calcular_iva()
{	
	if (Ctrl('n_porcentaje').GetXValue()!='')
	{
		var subtotal = Number(Ctrl('n_subtotal').GetXValue());
		var porcentaje = Number(Ctrl('n_porcentaje').GetXValue());
 		iva = subtotal*(porcentaje/100);

  	Ctrl('n_iva').SetCValue(iva.toFixed(2));
  }
  else
  {
  	Ctrl('n_iva').SetXValue();
  }
}


//Calcula el subtotal si cambia la cantidad o el precio unitario, 
function calcular_subtotal()
{
	var cant = Ctrl('n_cantidad').GetXValue();  
  var pu = Ctrl('n_precio_unitario').GetXValue();       
  var subtotal = Number(cant)*Number(pu);  
  Ctrl('n_subtotal').SetCValue(subtotal);
  calcular_iva();
  calcular_total();
}


//Calcula el total si cambia el subtotal o el importe del IVA
function calcular_total()
{	
	var subtotal = Ctrl('n_subtotal').GetXValue();
  var iva = Ctrl('n_iva').GetXValue();
  var total = Number(subtotal)+Number(iva);  
  Ctrl('n_total').SetCValue(total);
}


