function impuesto_onvalidate(pObj)
{
	if(Ctrl('main').GetMode()!='SHOW')
	{
		if(c_letra=='C' || c_letra=='X') return true;

		if(Ctrl('oi_impuesto').GetXValue()!='') return true;

		pObj.SetError('El valor es requerido.');
		return false;
	}

	return true;
}
